=<style>
  /* Base Booklet Styling */
  body { 
    font-family: 'Segoe UI', Roboto, Helvetica, Arial, sans-serif; 
    color: #1a1a1a; 
    line-height: 1.7; 
    padding: 40px; 
    background-color: #ffffff; 
  }
  .cover-header { 
    text-align: center; 
    padding: 60px 0 40px 0; 
    border-bottom: 5px solid #2980b9; 
    margin-bottom: 40px; 
  }
  .cover-header h1 { font-size: 3em; color: #2c3e50; margin: 0; }
  .cover-header p { font-size: 1.2em; color: #7f8c8d; }

  /* Typography */
  h2 { color: #2980b9; font-size: 1.8em; border-bottom: 2px solid #ecf0f1; padding-bottom: 10px; margin-top: 0; }
  h3 { color: #2c3e50; font-size: 1.3em; margin-top: 1.5em; margin-bottom: 0.5em; text-transform: uppercase; letter-spacing: 1px; }
  h4 { color: #34495e; font-size: 1.1em; margin-bottom: 10px; }
  .section-divider { border: 0; border-top: 2px solid #ecf0f1; margin: 30px 0; }

  /* Codeforces Raw Text Preservation */
  .cf-text { 
    background-color: #ffffff; 
    font-size: 1.05em; 
    white-space: pre-wrap; /* Crucial: Keeps paragraph breaks intact */
    word-wrap: break-word; 
    margin-bottom: 20px; 
  }

  /* Codeforces Authentic Input/Output Boxes */
  .cf-box { 
    border: 1px solid #bdc3c7; 
    margin-bottom: 25px; 
    border-radius: 6px; 
    overflow: hidden; 
  }
  .cf-title { 
    background-color: #f1f3f5; 
    padding: 8px 15px; 
    font-weight: bold; 
    font-size: 0.95em; 
    border-bottom: 1px solid #bdc3c7; 
    font-family: 'Consolas', 'Courier New', Courier, monospace; 
    color: #333; 
  }
  .cf-pre { 
    background-color: #ffffff; 
    color: #000000; 
    padding: 15px; 
    margin: 0; 
    font-family: 'Consolas', 'Courier New', Courier, monospace; 
    white-space: pre-wrap; 
    word-wrap: break-word; 
    font-size: 1.1em;
  }

  /* User and AI Coaching Sections */
  .thought-box { background-color: #fff8e1; border-left: 6px solid #f1c40f; padding: 20px; margin-bottom: 25px; border-radius: 4px; font-style: italic; }
  .ai-alignment { background-color: #e8f8f5; border-left: 6px solid #1abc9c; padding: 20px; margin-bottom: 25px; border-radius: 4px; }
  .ai-hints { background-color: #ebf5fb; border-left: 6px solid #3498db; padding: 20px; border-radius: 4px; margin-bottom: 25px; }
  .ai-hints ul { margin: 0; padding-left: 20px; }
  .ai-hints li { margin-bottom: 10px; }
  .ai-dry-run { background-color: #f5eef8; border-left: 6px solid #9b59b6; padding: 20px; margin-bottom: 25px; border-radius: 4px; }

  /* Code Editor Styling */
  pre { 
    background-color: #282c34; 
    color: #abb2bf; 
    padding: 20px; 
    border-radius: 8px; 
    white-space: pre-wrap; 
    word-wrap: break-word; 
    overflow-x: auto; 
    font-family: 'Consolas', 'Courier New', Courier, monospace; 
    font-size: 0.95em;
  }
  code { font-family: 'Consolas', 'Courier New', Courier, monospace; }

  /* The Disclaimer */
  .disclaimer-box { 
    margin-top: 40px; 
    padding: 20px; 
    background-color: #fdf2e9; 
    border-left: 6px solid #e67e22; 
    color: #d35400; 
    font-style: italic; 
    text-align: center; 
    border-radius: 4px; 
    font-size: 1em; 
    font-weight: bold;
  }
</style>

<div class="cover-header">
  <h1>📘 Codeforces Master Guide</h1>
  <p>Batch Analysis, Test Case Walkthroughs & Solutions</p>
</div>

{{ $json.output[0].content[0].text }}

<div class="disclaimer-box">
  ⚠️ Note: The AI's analysis and code can contain logical errors. Please consider this guide as a learning assistant, not an absolutely perfect answer key.
</div>
